bool dbIdValidation::isId(const char* inid)
{
  if (!inid) {
    return false;
  }

  for (; *inid; inid++) {
    if (isdigit(*inid) == 0) {
      return false;
    }
  }

  return true;
}

dbOrientType::dbOrientType(const char* orient)
{
  if (strcasecmp(orient, "R0") == 0) {
    _value = R0;
  } else if (strcasecmp(orient, "R90") == 0) {
    _value = R90;
  } else if (strcasecmp(orient, "R180") == 0) {
