    _value = MYR90;
  } else if (strcasecmp(orient, "MX") == 0) {
    _value = MX;
  } else if (strcasecmp(orient, "MXR90") == 0) {
    _value = MXR90;
  } else if (strcasecmp(orient, "N") == 0) {  // LEF/DEF style names
    _value = R0;
